class TreeNode:
    def __init__(self, val=0):
        self.val = val
        self.left = None
        self.right = None

# 递归前序遍历：根 -> 左 -> 右
def preorder(root):
    if not root:
        return []
    return [root.val] + preorder(root.left) + preorder(root.right)

# 迭代层序遍历（BFS），借助队列实现
from collections import deque

def level_order(root):
    if not root:
        return []
    result, queue = [], deque([root])
    while queue:
        node = queue.popleft()
        result.append(node.val)
        if node.left:
            queue.append(node.left)
        if node.right:
            queue.append(node.right)
    return result

# 构建示例树:     1
#                / \
#               2   3
root = TreeNode(1)
root.left = TreeNode(2)
root.right = TreeNode(3)
print(preorder(root))      # [1, 2, 3]
print(level_order(root))   # [1, 2, 3]

# 二叉搜索树（BST）的插入与查找
class BST:
    def __init__(self):
        self.root = None

    def insert(self, val):
        if not self.root:
            self.root = TreeNode(val)
            return
        # 迭代插入，维护BST性质
        node, parent = self.root, None
        while node:
            parent = node
            if val < node.val:
                node = node.left
            else:
                node = node.right
        # 连接新节点
        new_node = TreeNode(val)
        if val < parent.val:
            parent.left = new_node
        else:
            parent.right = new_node

    def search(self, val):
        node = self.root
        while node:
            if val == node.val:
                return True
            node = node.left if val < node.val else node.right
        return False

# 使用示例
bst = BST()
for v in [5, 3, 7, 1, 4]:
    bst.insert(v)
print(bst.search(4))   # True
print(bst.search(10))  # False
